+function drawStatusEffect(ctx: CanvasRenderingContext2D, state: AnimState, x: number, y: number, s: number, frame: number) {
+  if (state === 'working') {
+    // Glow effect around character
+    const glowRadius = 14 * s;
+    const glowAlpha = 0.4 + 0.3 * Math.sin(frame * 0.1);
+    const grad = ctx.createRadialGradient(x + 8 * s, y + 10 * s, glowRadius * 0.3, x + 8 * s, y + 10 * s, glowRadius);
+    grad.addColorStop(0, `rgba(255, 215, 0, ${glowAlpha.toFixed(2)})`);
+    grad.addColorStop(1, 'rgba(255, 215, 0, 0)');
+    ctx.fillStyle = grad;
+    ctx.beginPath();
+    ctx.arc(x + 8 * s, y + 10 * s, glowRadius, 0, Math.PI * 2);
+    ctx.fill();
+
+    // Rotating golden squares
+    for (let i = 0; i < 3; i++) {
+      const angle = (frame * 0.08 + i * 2.1) % (Math.PI * 2);
+      const sx = x + 8 * s + Math.cos(angle) * 12 * s;
+      const sy = y + 10 * s + Math.sin(angle) * 8 * s;
+      const size = (Math.sin(frame * 0.15 + i) * 0.5 + 1) * s;
+      ctx.fillStyle = P.gold[3 + (i % 2)];
+      ctx.fillRect(sx, sy, size, size);
+    }
+  } else if (state === 'idle') {
+    // ZZZ particles above head
+    const particleCount = 3;
+    for (let i = 0; i < particleCount; i++) {
+      const t = (frame * 0.05 + i * 10) % 60;
+      if (t < 40) {
+        const alpha = 1 - t / 40;
+        const px = x + 8 * s + i * 6 * s;
+        const py = y - 10 * s - t * 0.5 * s;
+        ctx.globalAlpha = alpha;
+        ctx.fillStyle = '#9999cc';
+        ctx.font = `${8 * s}px monospace`;
+        ctx.fillText('Z', px, py);
+        ctx.globalAlpha = 1;
+      }
+    }
+  } else if (state === 'stalled') {
+    // Red exclamation mark with pulsing background
+    const pulse = Math.sin(frame * 0.12) * 0.25 + 0.25;
+    ctx.fillStyle = `rgba(231, 76, 60, ${pulse})`;
+    ctx.fillRect(x - s, y - 2 * s, 18 * s, 24 * s);
+    ctx.fillStyle = '#e74c3c';
+    ctx.font = `bold ${10 * s}px sans-serif`;
+    ctx.fillText('!', x + 14 * s, y + 4 * s);
+  } else if (state === 'processing') {
+    // Spinning gears above head
+    const gearCount = 2;
+    for (let i = 0; i < gearCount; i++) {
+      const cx = x + 8 * s + (i === 0 ? -8 : 8) * s;
+      const cy = y - 6 * s;
+      const radius = 6 * s;
+      const rotation = frame * 0.1 * (i === 0 ? 1 : -1);
+      ctx.save();
+      ctx.translate(cx, cy);
+      ctx.rotate(rotation);
+      ctx.strokeStyle = '#888888';
+      ctx.lineWidth = 1.5;
+      // Draw gear teeth (8 teeth)
+      for (let t = 0; t < 8; t++) {
+        const angle = (t / 8) * Math.PI * 2;
+        const x1 = Math.cos(angle) * radius;
+        const y1 = Math.sin(angle) * radius;
+        const x2 = Math.cos(angle) * (radius + 3 * s);
+        const y2 = Math.sin(angle) * (radius + 3 * s);
+        ctx.beginPath();
+        ctx.moveTo(x1, y1);
+        ctx.lineTo(x2, y2);
+        ctx.stroke();
+      }
+      // Inner circle
+      ctx.beginPath();
+      ctx.arc(0, 0, radius * 0.6, 0, Math.PI * 2);
+      ctx.stroke();
+      ctx.restore();
+    }
+  } else if (state === 'reviewing') {
+    ctx.strokeStyle = P.gold[2]; ctx.lineWidth = 1.5;
+    ctx.beginPath(); ctx.arc(x + 16 * s, y + 2 * s, 3 * s, 0, Math.PI * 2); ctx.stroke();
+    ctx.beginPath(); ctx.moveTo(x + 18 * s, y + 4 * s); ctx.lineTo(x + 20 * s, y + 6 * s); ctx.stroke();
+  } else if (state === 'cancelled') {
+    ctx.fillStyle = 'rgba(50, 50, 60, 0.4)';
+    ctx.fillRect(x - s, y - 2 * s, 18 * s, 24 * s);
+  }
+}
